  1→package com.yottastudios.ns.collabspace.control.infrastructure.role;
  2→
  3→import cn.hutool.core.bean.BeanUtil;
  4→import com.yottastudios.ns.collabspace.control.infrastructure.permission.PermissionDefinition;
  5→
  6→import java.util.*;
  7→import java.util.stream.Collectors;
  8→
  9→abstract class AbstractControlRole implements ControlRole {
 10→
 11→    protected volatile Set<PermissionDefinition> permissions = new LinkedHashSet<>();
 12→
 13→    private final boolean inherit;
 14→
 15→    public AbstractControlRole(boolean inherit) {
 16→        this.inherit = inherit;
 17→    }
 18→
 19→    @Override
 20→    public boolean isInherit() {
 21→        return this.inherit;
 22→    }
 23→
 24→    @Override
 25→    public Set<PermissionDefinition> getPermissions() {
 26→        return this.permissions;
 27→    }
 28→
 29→    @Override
 30→    public Set<PermissionDefinition> getPermissions(String nodeId) {
 31→        return this.permissions;
 32→    }
 33→
 34→    @Override
 35→    public Map<Integer, Long> getGroupPermissionBit() {
 36→        Map<Integer, List<PermissionDefinition>> mapGroups = permissions.stream().distinct()
 37→                .sorted(Comparator.comparing(PermissionDefinition::getGroup))
 38→                .collect(Collectors.groupingBy(PermissionDefinition::getGroup, Collectors.toList()));
 39→        return mapGroups.entrySet().stream()
 40→                .collect(Collectors.toMap(Map.Entry::getKey,
 41→                        entry ->
 42→                                entry.getValue().stream()
 43→                                        .mapToLong(PermissionDefinition::getValue)
 44→                                        .reduce(0L, (left, right) -> left | right)));
 45→    }
 46→
 47→    @Override
 48→    public boolean hasPermission(PermissionDefinition permission) {
 49→        int group = permission.getGroup();
 50→        long value = permission.getValue();
 51→        return !((getGroupPermissionBit().get(group) & value) == 0);
 52→    }
 53→
 54→    @Override
 55→    public long getBits() {
 56→        return getGroupPermissionBit().values().stream().reduce(0L, (left, right) -> left | right);
 57→    }
 58→
 59→    @Override
 60→    public int compareTo(ControlRole other) {
 61→        return Long.compare(getBits(), other.getBits());
 62→    }
 63→
 64→    @Override
 65→    public boolean isEqualTo(ControlRole other) {
 66→        return this.compareTo(other) == 0;
 67→    }
 68→
 69→    @Override
 70→    public boolean isGreaterThan(ControlRole other) {
 71→        return this.compareTo(other) > 0;
 72→    }
 73→
 74→    @Override
 75→    public boolean isGreaterThanOrEqualTo(ControlRole other) {
 76→        return this.compareTo(other) >= 0;
 77→    }
 78→
 79→    @Override
 80→    public boolean isLessThan(ControlRole other) {
 81→        return this.compareTo(other) < 0;
 82→    }
 83→
 84→    @Override
 85→    public boolean isLessThanOrEqualTo(ControlRole other) {
 86→        return this.compareTo(other) <= 0;
 87→    }
 88→
 89→    @Override
 90→    public <T> T permissionToBean(Class<T> beanClass) {
 91→        Map<String, Boolean> map = getPermissions().stream()
 92→                .collect(HashMap::new, (m, v) -> m.put(v.getCode(), true), HashMap::putAll);
 93→        return BeanUtil.toBeanIgnoreError(map, beanClass);
 94→    }
 95→
 96→    @Override
 97→    public String toString() {
 98→        return super.toString();
 99→    }
100→}

