 1→package com.yottastudios.ns.collabspace.control.infrastructure.role;
 2→
 3→import cn.hutool.core.lang.Assert;
 4→
 5→import java.util.*;
 6→
 7→import static com.yottastudios.ns.collabspace.control.infrastructure.role.RoleConstants.*;
 8→
 9→public class ControlRoleManager {
10→    private static final Map<String, ControlRole> NODE_CONTROL_ROLE_MAP;
11→    static {
12→        // node role container
13→        NODE_CONTROL_ROLE_MAP = new HashMap<>(16);
14→        registerNodeRole(SpaceNode.READER, new NodeReaderRole());
15→        registerNodeRole(SpaceNode.EDITOR, new NodeEditorRole());
16→        registerNodeRole(SpaceNode.MANAGER, new NodeManagerRole());
17→    }
18→
19→    private static void registerNodeRole(String name, ControlRole role) {
20→        if (name != null) {
21→            NODE_CONTROL_ROLE_MAP.put(name, role);
22→        }
23→    }
24→
25→    public static ControlRole parseNodeRole(String roleCode) {
26→        Assert.isTrue(NODE_CONTROL_ROLE_MAP.containsKey(roleCode), "node role is not exist");
27→        return NODE_CONTROL_ROLE_MAP.get(roleCode);
28→    }
29→
30→    public static List<ControlRole> parseAndSortNodeRole(Collection<String> roleCodes) {
31→        List<ControlRole> sortedList = roleCodes.stream().reduce(new ArrayList<>(),
32→                (controlRoles, item) -> {
33→                    controlRoles.add(parseNodeRole(item));
34→                    return controlRoles;
35→                },
36→                (controlRoles, childRoles) -> {
37→                    controlRoles.addAll(childRoles);
38→                    return controlRoles;
39→                });
40→        Collections.sort(sortedList);
41→        return sortedList;
42→    }
43→
44→    public static ControlRole getTopNodeRole(Collection<String> roleCodes) {
45→        List<ControlRole> roles = parseAndSortNodeRole(roleCodes);
46→        return roles.getLast();
47→    }
48→
49→}
