 35→@Tag(name = "Node - Share Api")
 36→@RestController
 37→@ApiResource(path = "/node")
 38→@Slf4j
 39→@RequiredArgsConstructor
 40→@Validated
 41→public class NodeShareController {
 42→
 43→    @Resource
 44→    private NodeShareQueryManager nodeShareQueryManager;
 45→
 46→    @Resource
 47→    private NodeShareUpdateManager nodeShareUpdateManager;
 48→
 49→    @Resource
 50→    private PermissionChecker permissionChecker;
 51→
 52→    @Resource
 53→    private EventBusFacade eventBusFacade;
 54→
 55→    // ==================== node-level share ====================
 56→
 57→    @GetResource(path = "/{spaceNodeId}/getNodeShare")
 58→    @Parameters({
 59→            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
 60→                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
 61→    })
 62→    @Operation(summary = "Get node share configs")
 63→    public ResponseData<AllShareConfigsVo> getNodeShare(@PathVariable Long spaceNodeId) {
 64→        AllShareConfigsVo result = nodeShareQueryManager.getNodeShare(spaceNodeId);
 65→        return ResponseData.success(result);
 66→    }
 67→
 68→    @PostResource(path = "/batchGetNodeShare")
 69→    @Parameters({
 70→            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
 71→                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
 72→    })
 73→    @Operation(summary = "Batch get node share configs")
 74→    public ResponseData<List<AllShareConfigsVo>> batchGetNodeShare(@RequestBody @Valid BatchGetNodeShareRo ro) {
 75→        List<AllShareConfigsVo> result = nodeShareQueryManager.batchGetNodeShare(ro.getAppSpaceNodeIds());
 76→        return ResponseData.success(result);
 77→    }
 78→
 79→    @PostResource(path = "/{spaceNodeId}/createNodeShare")
 80→    @Parameters({
 81→            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
 82→                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
 83→    })
 84→    @Operation(summary = "Create node share")
 85→    public ResponseData<NodeShareVo> createNodeShare(
 86→            @PathVariable Long spaceNodeId,
 87→            @RequestBody @Valid CreateNodeShareRo ro) {
 88→        Long userId = SessionContext.getUserId();
 89→        permissionChecker.requireUser(userId).onNode(spaceNodeId).needPermission(NodePermission.SHARE_NODE);
 90→        NodeShareProps propsVo = NodeShareProps.fromBean(ro.getProps());
 91→        NodeShareVo result = nodeShareUpdateManager.createNodeShare(spaceNodeId, propsVo, ro.getShareType());
 92→        eventBusFacade.onEvent(new ShareCreateEvent(result));
 93→        return ResponseData.success(result);
