 74→    @Operation(summary = "Create Space Node")
 75→    public ResponseData<TreeNode<SpaceNodeVo>> createSpaceNode(@RequestBody @Valid SpaceNodeCreateRo ro) {
 76→        Long userId = SessionContext.getUserId();
 77→        String spaceId = SpaceHolder.get();
 78→        // 鉴权
 79→        if (ro.getParentId() == null ||  ro.getParentId() == 0) {
 80→            // 创建在根节点, 取space默认权限
 81→            permissionChecker.requireUser(userId).onSpaceDefaultNode(spaceId).needPermission(NodePermission.CREATE_NODE);
 82→        } else {
 83→            // 在已有节点下创建, 取父节点权限
 84→            NodeEntity nodeEntity = nodeService.getById(ro.getParentId());
 85→            if (nodeEntity == null) {
 86→                throw new BusinessException(SpaceNodeException.NOT_EXIST);
 87→            }
 88→            permissionChecker.requireUser(userId).onNode(nodeEntity.getRelId()).needPermission(NodePermission.CREATE_NODE);
 89→        }
 90→
 91→        TreeNode<SpaceNodeVo> result = spaceNodeUpdateManager.createSpaceNode(spaceId, userId, ro);
 92→        return ResponseData.success(result);
 93→    }
