 88→    @Override
 89→    public List<TreeNode<SpaceNodeVo>> getSpaceNodeTree(String spaceId) {
 90→        long t0 = System.currentTimeMillis();
 91→
 92→        // 联表查询：一次 DB 同时取 space_node 数据 + node 树结构，省去 buildNodeTree 内部的 listByRelIds 二次查询
 93→        List<SpaceNodeWithNodeDto> combined = spaceNodeService.listBySpaceIdWithNodeInfo(spaceId, false);
 94→        long t1 = System.currentTimeMillis();
 95→        log.info("[2009-perf][getSpaceNodeTree] spaceId={} nodeCount={} listBySpaceIdJoinNode={}ms", spaceId, combined.size(), t1 - t0);
 96→
 97→        List<SpaceNodeEntity> entities = new ArrayList<>(combined.size());
 98→        List<NodeEntity> nodeEntities = new ArrayList<>(combined.size());
 99→        for (SpaceNodeWithNodeDto dto : combined) {
100→            entities.add(dto);
101→            nodeEntities.add(dto.toNodeEntity());
102→        }
103→
104→        List<SpaceNodeVo> vos = spaceNodeTransfer.toSpaceNodeVoWithRole(entities);
105→        long t2 = System.currentTimeMillis();
106→        log.info("[2009-perf][getSpaceNodeTree] spaceId={} toSpaceNodeVoWithRole={}ms", spaceId, t2 - t1);
107→
108→        // 使用预取的 nodeEntities，跳过 buildNodeTree 内部的 listByRelIds
109→        List<TreeNode<SpaceNodeVo>> result = treeNodeTemplate.buildNodeTree(vos, nodeEntities, ROOT_PARENT_ID);
110→        long t3 = System.currentTimeMillis();
111→        log.info("[2009-perf][getSpaceNodeTree] spaceId={} buildNodeTree={}ms total={}ms", spaceId, t3 - t2, t3 - t0);
112→
113→        return result;
114→    }
