116→    @Override
117→    public List<TreeNode<SpaceNodeVo>> getSpaceNodeTreeWithoutRole(String spaceId) {
118→        List<SpaceNodeEntity> spaceNodeEntities = spaceNodeService.listBySpaceId(spaceId, false);
119→        List<SpaceNodeVo> vos = spaceNodeTransfer.toSpaceNodeVo(spaceNodeEntities);
120→        return treeNodeTemplate.buildNodeTree(vos);
121→    }
122→
123→    @Override
124→    public TreeNode<SpaceNodeVo> getSubSpaceNodeTreeWithoutRole(Long parentSpaceNodeId) {
125→        List<NodeEntity> nodeEntities = treeNodeTemplate.listSubtreeByRelId(parentSpaceNodeId);
126→        List<Long> spaceNodeIds = nodeEntities.stream().map(NodeEntity::getRelId).toList();
127→        List<SpaceNodeEntity> spaceNodeEntities = spaceNodeService.listByIds(spaceNodeIds);
128→        List<SpaceNodeVo> vos = spaceNodeTransfer.toSpaceNodeVo(spaceNodeEntities);
129→        if (CollectionUtils.isEmpty(vos)) {
130→            log.warn("No sub nodes found for {}",  parentSpaceNodeId);
131→            return null;
132→        }
133→        NodeEntity rootNode = nodeEntities.stream()
134→                .filter(nodeEntity -> Objects.equals(nodeEntity.getRelId(), parentSpaceNodeId))
135→                .findFirst()
136→                .orElse(null);
137→        if (rootNode == null) {
138→            log.warn("No root node found for {}", parentSpaceNodeId);
139→            return null;
140→        }
141→        Long rootId = rootNode.getId();
142→        SpaceNodeVo rootVo = vos.stream()
143→                .filter(spaceNodeVo -> Objects.equals(spaceNodeVo.getId(), parentSpaceNodeId))
144→                .findFirst()
145→                .orElse(null);
146→
147→        List<TreeNode<SpaceNodeVo>> children = treeNodeTemplate.buildNodeTree(vos, nodeEntities, rootId);
