428→    private List<TreeNode<SpaceNodeVo>> keepDataSheetAndAncestors(List<TreeNode<SpaceNodeVo>> nodes) {
429→        if (nodes == null || nodes.isEmpty()) return List.of();
430→
431→        List<TreeNode<SpaceNodeVo>> result = new ArrayList<>();
432→        for (TreeNode<SpaceNodeVo> n : nodes) {
433→            TreeNode<SpaceNodeVo> kept = pruneByDataSheet(n);
434→            if (kept != null) result.add(kept);
435→        }
436→        return result;
437→    }
438→
439→    private TreeNode<SpaceNodeVo> pruneByDataSheet(TreeNode<SpaceNodeVo> node) {
440→        if (node == null) return null;
441→
442→        // 1) 先处理子节点（后序）
443→        List<TreeNode<SpaceNodeVo>> children = node.getChildren();
444→        List<TreeNode<SpaceNodeVo>> keptChildren = new ArrayList<>();
445→        if (children != null && !children.isEmpty()) {
446→            for (TreeNode<SpaceNodeVo> c : children) {
447→                TreeNode<SpaceNodeVo> kept = pruneByDataSheet(c);
448→                if (kept != null) keptChildren.add(kept);
449→            }
450→        }
451→        node.setChildren(keptChildren);
452→
453→        // 2) 判断当前节点是否保留
454→        Integer type = node.getData() == null ? null : node.getData().getType();
455→        boolean isDataSheet = SpaceNodeTypeEnum.DATASHEET.getValue().equals(type);
456→        boolean hasKeptChild = !keptChildren.isEmpty();
457→
458→        if (isDataSheet || hasKeptChild) {
459→            return node;
460→        }
461→        return null;
462→    }
