344→    /**
345→     * @param outSpaceMap 若非null，USER_ID+SPACE_NODE 分支会将完整的 spaceId→nodeIds 映射写入此Map，
346→     *                    供调用方复用，避免重复 DB 查询。
347→     */
348→    protected ControlRoleDict doExecute(Principal principal, ControlId controlId, ControlRequestWrapper requestWrapper, Map<String, List<Long>> outSpaceMap) {
349→        if (principal.getPrincipalType() == PrincipalType.UNIT_ID) {
350→            return this.doExecute(List.of(principal.getPrincipal()), controlId, requestWrapper);
351→        } else if (principal.getPrincipalType() == PrincipalType.USER_ID) {
352→            ControlRoleDict controlRoleDict = ControlRoleDict.create();
353→            if (controlId.getControlType() == ControlType.SPACE_NODE) {
354→                long td0 = System.currentTimeMillis();
355→                List<Long> spaceNodeIds = controlId.getControlIds().stream().map(Long::parseLong).toList();
356→                Long userId = principal.getPrincipal();
357→                Map<Long, String> snapshotNodeToSpaceMap = spaceNodeService.getSnapshotNodeIdToSpaceIdMap(spaceNodeIds);
358→                // find space-spaceNode relation
359→                Map<String, List<Long>> spaceIdToSpaceNodeIdMap = spaceNodeQueryManager.getSpaceIdToSpaceNodeIdMap(spaceNodeIds);
360→                long td1 = System.currentTimeMillis();
361→                log.info("[2009-perf][doExecute] getSpaceIdToSpaceNodeIdMap={}ms userId={} spaceCount={}", td1 - td0, userId, spaceIdToSpaceNodeIdMap.size());
362→
363→                // 暴露给调用方复用（在 managed space remove 之前捕获完整映射）
364→                if (outSpaceMap != null) {
365→                    outSpaceMap.putAll(spaceIdToSpaceNodeIdMap);
366→                }
367→
368→                // filter managed nodes and set top role
369→                List<SpaceEntity> managedSpaces = spaceQueryManager.getMemberManagedSpace(userId);
370→                long td2 = System.currentTimeMillis();
371→                log.info("[2009-perf][doExecute] getMemberManagedSpace={}ms userId={} managedSpaceCount={}", td2 - td1, userId, managedSpaces.size());
372→
373→                for (SpaceEntity space : managedSpaces) {
374→                    List<Long> managedSpaceNodeIds = spaceIdToSpaceNodeIdMap.get(space.getSpaceId());
375→                    if (CollectionUtils.isNotEmpty(managedSpaceNodeIds)) {
376→                        ControlRole topRole = this.getTopRole(controlId.getControlType());
377→                        managedSpaceNodeIds.forEach(cId -> controlRoleDict.put(cId.toString(), topRole));
378→                        spaceIdToSpaceNodeIdMap.remove(space.getSpaceId());
379→                    }
380→                }
381→                // find units in all no-manage space
382→                List<Long> allUnitIds = new ArrayList<>();
383→                List<Long> noManagedSpaceNodeIds = new ArrayList<>();
384→                Set<String> userInSpaceIds = managedSpaces.stream().map(SpaceEntity::getSpaceId).collect(Collectors.toSet());
385→                log.info("[2009-perf][doExecute] nonManagedSpaceCount={} userId={}", spaceIdToSpaceNodeIdMap.size(), userId);
386→                for (Map.Entry<String, List<Long>> entry : spaceIdToSpaceNodeIdMap.entrySet()) {
387→                    String spaceId = entry.getKey();
388→                    long tg0 = System.currentTimeMillis();
389→                    List<Long> userUnitsInSpace = apitableGrpcClientService.getUnitsByMember(userId, spaceId);// todo batch&&cache
390→                    log.info("[2009-perf][doExecute] getUnitsByMember={}ms userId={} spaceId={} unitCount={}", System.currentTimeMillis() - tg0, userId, spaceId, userUnitsInSpace == null ? 0 : userUnitsInSpace.size());
391→                    boolean isUserInSpace = CollectionUtils.isNotEmpty(userUnitsInSpace);
392→
393→                    // only process nodes if user is a member of the space
394→                    if (isUserInSpace) {
395→                        userInSpaceIds.add(spaceId);
396→                        allUnitIds.addAll(userUnitsInSpace);
397→
398→                        List<Long> nodeIdsInSpace = entry.getValue();
399→                        if (CollectionUtils.isNotEmpty(nodeIdsInSpace)) {
400→                            noManagedSpaceNodeIds.addAll(nodeIdsInSpace);
401→                        }
402→                    }
403→                }
404→                // snapshot -> Reader
405→                for (Map.Entry<Long, String> entry : snapshotNodeToSpaceMap.entrySet()) {
406→                    Long snapshotNodeId = entry.getKey();
407→                    String spaceId = entry.getValue();
408→                    if (userInSpaceIds.contains(spaceId)) {
409→                        controlRoleDict.put(snapshotNodeId.toString(), new NodeReaderRole());
410→                        noManagedSpaceNodeIds.remove(snapshotNodeId);
411→                    }
412→                }
413→                // execute noManagedSpaceNodes
414→                long td3 = System.currentTimeMillis();
415→                ControlRoleDict excutedControlRoleDict = doExecute(allUnitIds, ControlIdBuilder.spaceNodeIds(noManagedSpaceNodeIds), requestWrapper);
416→                log.info("[2009-perf][doExecute] aclCompute={}ms noManagedNodeCount={}", System.currentTimeMillis() - td3, noManagedSpaceNodeIds.size());
417→
418→                // merge dict
419→                return controlRoleDict.merge(excutedControlRoleDict);
420→            }
421→            // other control type
422→            return controlRoleDict;
423→        } else {
424→            throw new UnknownPrincipalTypeException(principal.getPrincipalType());
425→        }
426→    }
427→
428→    protected ControlRoleDict doExecute(List<Long> principalFromUnitIds, ControlId controlId, ControlRequestWrapper requestWrapper) {
429→        ControlRequest request = createRequest(principalFromUnitIds, controlId);
430→        if (requestWrapper != null) {
431→            requestWrapper.doWrapper(request);
432→        }
433→        return request.execute();
434→    }
