  2→
  3→import com.yottastudios.ns.collabspace.control.infrastructure.permission.NodePermission;
  4→import com.yottastudios.ns.collabspace.control.infrastructure.permission.PermissionDefinition;
  5→import com.yottastudios.ns.collabspace.control.infrastructure.policy.SpacePermissionPolicy;
  6→
  7→import java.util.*;
  8→import java.util.stream.Collectors;
  9→
 10→/**
 11→ * 基于 SpacePermissionPolicy 强制覆盖原 ControlRole 的 Permissions
 12→ */
 13→public class SpacePolicyEnforcedControlRole extends AbstractControlRole {
 14→
 15→    private final ControlRole delegate;
 16→    private final SpacePermissionPolicy policy;
 17→
 18→    public SpacePolicyEnforcedControlRole(ControlRole delegate,
 19→                                          SpacePermissionPolicy policy) {
 20→        super(delegate.isInherit());
 21→        this.delegate = delegate;
 22→        this.policy = policy;
 23→    }
 24→
 25→    @Override
 26→    public String getRoleTag() {
 27→        return delegate.getRoleTag();
 28→    }
 29→
 30→    @Override
 31→    public boolean isAdmin() {
 32→        return delegate.isAdmin();
 33→    }
 34→
 35→    @Override
 36→    public Set<PermissionDefinition> getPermissions() {
 37→        Set<PermissionDefinition> base = delegate.getPermissions();
 38→        if (policy == null) {
 39→            return base;
 40→        }
 41→        return applyPolicy(base, delegate.getRoleTag());
 42→    }
 43→
 44→    @Override
 45→    public Set<PermissionDefinition> getPermissions(String nodeId) {
 46→        Set<PermissionDefinition> base = delegate.getPermissions(nodeId);
 47→        if (policy == null) {
 48→            return base;
 49→        }
 50→        return applyPolicy(base, delegate.getRoleTag());
 51→    }
 52→
 53→    private Set<PermissionDefinition> applyPolicy(Set<PermissionDefinition> base, String selfRoleTag) {
 54→        Set<NodePermission> baseNodePerms = extractNodePermissions(base);
 55→        Set<NodePermission> effectiveNodePerms = new HashSet<>();
 56→
 57→        Map<String, String> minRoleByCode = policy.asMap();
 58→
 59→        for (NodePermission p : NodePermission.values()) {
 60→            String code = p.getCode();
 61→            String minRoleTag = minRoleByCode.get(code);
 62→            if (minRoleTag != null) {
 63→                if (roleGreaterOrEqual(selfRoleTag, minRoleTag)) {
 64→                    effectiveNodePerms.add(p);
 65→                }
 66→                continue;
 67→            }
 68→            if (baseNodePerms.contains(p)) {
 69→                effectiveNodePerms.add(p);
 70→            }
 71→        }
 72→
 73→        return mergePermissions(base, effectiveNodePerms);
 74→    }
 75→
 76→    private boolean roleGreaterOrEqual(String selfTag, String requiredTag) {
 77→        if (requiredTag == null) return true;
 78→        ControlRole self = ControlRoleManager.parseNodeRole(selfTag);
 79→        ControlRole required = ControlRoleManager.parseNodeRole(requiredTag);
 80→        return self != null && required != null && self.isGreaterThanOrEqualTo(required);
 81→    }
 82→
 83→    private Set<NodePermission> extractNodePermissions(Set<PermissionDefinition> defs) {
 84→        Set<NodePermission> r = new HashSet<>();
 85→        for (PermissionDefinition d : defs) {
 86→            if (d instanceof NodePermission) {
 87→                r.add((NodePermission) d);
 88→            }
 89→        }
 90→        return r;
 91→    }
 92→
 93→    private Set<PermissionDefinition> mergePermissions(Set<PermissionDefinition> base,
 94→                                                       Set<NodePermission> effectiveNodePerms) {
 95→        Set<PermissionDefinition> merged = new HashSet<>();
 96→        for (PermissionDefinition d : base) {
 97→            if (d instanceof NodePermission) continue;
 98→            merged.add(d);
 99→        }
100→        merged.addAll(effectiveNodePerms);
101→        return merged;
102→    }
103→
104→    @Override
105→    public Map<Integer, Long> getGroupPermissionBit() {
106→        Set<PermissionDefinition> effective = getPermissions();
107→        Map<Integer, List<PermissionDefinition>> mapGroups = effective.stream().distinct()
108→                .sorted(Comparator.comparing(PermissionDefinition::getGroup))
109→                .collect(Collectors.groupingBy(PermissionDefinition::getGroup, Collectors.toList()));
110→        Map<Integer, Long> bits = new HashMap<>();
111→        for (Map.Entry<Integer, List<PermissionDefinition>> e : mapGroups.entrySet()) {
112→            long v = 0L;
113→            for (PermissionDefinition pd : e.getValue()) {
114→                v |= pd.getValue();
115→            }
116→            bits.put(e.getKey(), v);
117→        }
118→        return bits;
119→    }
120→
121→    @Override
122→    public long getBits() {
123→        return getGroupPermissionBit().values().stream().reduce(0L, (left, right) -> left | right);
124→    }
125→
126→    @Override
127→    public boolean hasPermission(PermissionDefinition permission) {
128→        return getPermissions().contains(permission);
129→    }
130→}
