228→    private boolean isEmailAllowed(String allowedEmailsJson, String email, boolean allowAnonymous) {
229→        // 未配置 -> 放行
230→        if (StringUtils.isBlank(allowedEmailsJson)) {
231→            return true;
232→        }
233→        // 只读，放行
234→        if (allowAnonymous) {
235→            return true;
236→        }
237→        List<String> emails = JSONUtil.toList(allowedEmailsJson, String.class);
238→        if (CollectionUtils.isEmpty(emails)) {
239→            return true;
240→        }
241→        return emails.contains(email);
242→    }
