244→    /**
245→     * 按 shareScope → nodeScope 顺序校验
246→     */
247→    private boolean checkAccess(ShareScopeEntity shareScope, NodeShareScopeEntity nodeScope, String email, boolean allowAnonymous) {
248→        if (shareScope != null && isEmailAllowed(shareScope.getAllowedEmails(), email, allowAnonymous)) {
249→            return true;
250→        }
251→        return nodeScope == null || isEmailAllowed(nodeScope.getAllowedEmails(), email, allowAnonymous);
252→    }
