254→    private void populateFolderShareSubtree(NodeShareTreeVo rootTreeVo) {
255→        Long rootParentId = rootTreeVo.getSpaceNodeId();
256→        TreeNode<SpaceNodeVo> subSpaceNodeTree = spaceNodeQueryManager.getSubSpaceNodeTreeWithoutRole(rootParentId);
257→        List<TreeNode<SpaceNodeVo>> descendants = TreeUtil.collectDescendant(subSpaceNodeTree);
258→        List<Integer> shareableTypeValues = AppSpaceNodeActionFactory.SHAREABLE_TYPES.stream().map(SpaceNodeTypeEnum::getValue).toList();
259→        List<Long> subSpaceNodeIds = descendants.stream()
260→                .filter(n -> n.getData() != null && n.getData().getType() != null && shareableTypeValues.contains(n.getData().getType()))
261→                .map(TreeNode::getRelId)
262→                .collect(Collectors.toList());
263→        // subNodeShares是专为文件夹分享创建的一套同时有只读+可编辑+可存副本的一套权限, 只取和rootTreeVo的权限相同的
264→        Long propBits = rootTreeVo.getProps().toBits();
265→        // 临时加个锁, 防止在文件夹分享创建后, 异步任务生成子节点分享事务结束前重复插入
266→        List<NodeShareEntity> subNodeShares = lockService.tryLockWithRetry(
267→                RedisConstants.getNodeTreeShareOperateKey(rootParentId),
268→                () -> nodeShareUpdateManager.ensureSubNodeSharesExists(subSpaceNodeIds, propBits)
269→        );
270→
271→        List<NodeShareTreeVo> children = NodeShareTreeVo.buildShareTree(subSpaceNodeTree, subNodeShares);
272→        rootTreeVo.setChildren(children);
273→    }
