275→    @Override
276→    public List<AllShareConfigsVo> batchGetNodeShare(List<String> appSpaceNodeIds) {
277→        if (CollectionUtils.isEmpty(appSpaceNodeIds)) {
278→            return new ArrayList<>();
279→        }
280→
281→        List<SpaceNodeEntity> spaceNodeEntities = spaceNodeService.listByAppSpaceNodeIds(appSpaceNodeIds);
282→        if (CollectionUtils.isEmpty(spaceNodeEntities)) {
283→            log.warn("未找到对应的SpaceNode，appSpaceNodeIds={}", appSpaceNodeIds);
284→            return new ArrayList<>();
285→        }
286→
287→        List<Long> spaceNodeIds = spaceNodeEntities.stream()
288→                .map(SpaceNodeEntity::getId)
289→                .collect(Collectors.toList());
290→
291→        List<NodeShareEntity> allNodeShareEntities = nodeShareService.listBySpaceNodeIds(spaceNodeIds);
292→        Map<Long, List<NodeShareEntity>> spaceNodeIdToSharesMap = allNodeShareEntities.stream()
293→                .collect(Collectors.groupingBy(NodeShareEntity::getSpaceNodeId));
294→
295→        List<NodeShareScopeEntity> allNodeShareScopeEntities = nodeShareScopeService.listBySpaceNodeIds(spaceNodeIds);
296→        Map<Long, NodeShareScopeEntity> spaceNodeIdToScopeMap = allNodeShareScopeEntities.stream()
297→                .collect(Collectors.toMap(NodeShareScopeEntity::getSpaceNodeId, entity -> entity));
298→
299→        List<String> allShareIds = allNodeShareEntities.stream()
300→                .map(NodeShareEntity::getShareId)
301→                .collect(Collectors.toList());
302→        List<ShareScopeEntity> allShareScopeEntities = shareScopeService.listByShareIds(allShareIds);
303→        Map<String, ShareScopeEntity> shareIdToScopeMap = allShareScopeEntities.stream()
304→                .collect(Collectors.toMap(ShareScopeEntity::getShareId, entity -> entity));
305→
306→        List<AllShareConfigsVo> result = new ArrayList<>();
307→
308→        for (SpaceNodeEntity spaceNodeEntity : spaceNodeEntities) {
309→            Long spaceNodeId = spaceNodeEntity.getId();
310→
311→            // spaceNodeVo
312→            SpaceNodeVo spaceNodeVo = spaceNodeTransfer.toSpaceNodeVo(spaceNodeEntity);
313→
314→            // node-level shares
315→            List<NodeShareEntity> nodeShareEntities = spaceNodeIdToSharesMap.getOrDefault(spaceNodeId, List.of());
316→            List<NodeShareVo> nodeShareVos = nodeShareEntities.stream()
317→                    .map(NodeShareVo::new)
318→                    .collect(Collectors.toList());
319→
320→            // node-level scope
321→            NodeShareScopeEntity nodeShareScopeEntity = spaceNodeIdToScopeMap.get(spaceNodeId);
322→            NodeShareScopeVo nodeShareScopeVo = new NodeShareScopeVo(nodeShareScopeEntity);
323→
324→            // shareId-level scopes
325→            List<ShareScopeVo> shareScopeVos = nodeShareEntities.stream()
326→                    .map(NodeShareEntity::getShareId)
327→                    .map(shareIdToScopeMap::get)
328→                    .filter(java.util.Objects::nonNull)
329→                    .map(ShareScopeVo::new)
330→                    .collect(Collectors.toList());
331→
332→            AllShareConfigsVo allShareConfigsVo = AllShareConfigsVo.builder()
333→                    .spaceNode(spaceNodeVo)
334→                    .nodeShares(nodeShareVos)
335→                    .nodeShareScope(nodeShareScopeVo)
336→                    .shareScopes(shareScopeVos)
337→                    .build();
338→
339→            result.add(allShareConfigsVo);
340→        }
341→
342→        return result;
343→    }
