25→    public List<SpaceNodeVo> filterAndSetRole(Long userId, List<SpaceNodeVo> vos) {
26→        if (userId == null || CollectionUtils.isEmpty(vos)) return vos;
27→
28→        long t0 = System.currentTimeMillis();
29→        List<Long> spaceNodeIds = vos.stream().map(SpaceNodeVo::getId).collect(Collectors.toList());
30→        ControlRoleDict controlRoleDict = controlTemplate.fetchSpaceNodeRole(userId, spaceNodeIds);
31→        long t1 = System.currentTimeMillis();
32→        log.info("[2009-perf][filterAndSetRole] fetchSpaceNodeRole={}ms userId={} nodeCount={}", t1 - t0, userId, spaceNodeIds.size());
33→
34→        // 同一批请求中相同 bits 的角色 permissionToBean 结果完全一样，缓存复用避免重复反射
35→        Map<Long, NodePermissionView> permissionViewCache = new HashMap<>();
36→
37→        List<SpaceNodeVo> result = vos.stream()
38→                .filter(vo -> {
39→                    ControlRole controlRole = controlRoleDict.get(vo.getId().toString());
40→
41→                    if (controlRole == null) {
42→                        log.debug("user: {} not have role in spaceNode: {}-{}", userId, vo.getId(), vo.getName());
43→                        return false;
44→                    } else {
45→                        vo.setRole(controlRole.getRoleTag());
46→                        NodePermissionView permissions = permissionViewCache.computeIfAbsent(
47→                                controlRole.getBits(),
48→                                bits -> controlRole.permissionToBean(NodePermissionView.class)
49→                        );
50→                        vo.setPermissions(permissions);
51→                        return true;
52→                    }
53→                })
54→                .toList();
55→        long t2 = System.currentTimeMillis();
56→        log.info("[2009-perf][filterAndSetRole] roleMapping={}ms visibleCount={} permissionViewKinds={}", t2 - t1, result.size(), permissionViewCache.size());
57→
58→        return result;
59→    }
60→
61→    public List<SpaceNodeVo> filterAndSetRole(List<SpaceNodeVo> vos) {
62→        Long userId = UserHolder.get();
63→        return filterAndSetRole(userId, vos);
64→    }
